#include "kernel.h"

#include <cuda.h>
#include <cuda_bf16.h>
#include <cuda_runtime.h>

#include <ATen/cuda/CUDAContext.h>

#ifndef CUDA_CHECK
#define CUDA_CHECK(expr)                                                        \
  do {                                                                          \
    cudaError_t _err = (expr);                                                  \
    if (_err != cudaSuccess) {                                                  \
      printf("CUDA Error %s at %s:%d\n", cudaGetErrorString(_err), __FILE__,    \
             __LINE__);                                                         \
    }                                                                           \
  } while (0)
#endif

// ---- helpers ----
__device__ __forceinline__ float neg_inf_f() { return -INFINITY; }

__device__ __forceinline__ float warp_reduce_sum(float v) {
#pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffff, v, offset);
  }
  return v;
}

template<int MAX_WARPS>
__device__ __forceinline__ float block_reduce_sum(float v) {
  __shared__ float smem[MAX_WARPS];
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;
  v = warp_reduce_sum(v);
  if (lane == 0) smem[wid] = v;
  __syncthreads();
  // only threads in first warp read smem
  float out = 0.0f;
  if (wid == 0) {
    out = (lane < (blockDim.x >> 5)) ? smem[lane] : 0.0f;
    out = warp_reduce_sum(out);
  }
  // broadcast to all threads
  out = __shfl_sync(0xffffffff, out, 0);
  return out;
}

__device__ __forceinline__ __nv_bfloat16 ld_bf16(const at::BFloat16* p) {
  return *reinterpret_cast<const __nv_bfloat16*>(p);
}
__device__ __forceinline__ float bf16_to_f32(const at::BFloat16* p) {
  return __bfloat162float(ld_bf16(p));
}
__device__ __forceinline__ void st_bf16(at::BFloat16* p, float v) {
  *reinterpret_cast<__nv_bfloat16*>(p) = __float2bfloat16_rn(v);
}

__device__ __forceinline__ void load_bf16x4_as_f32(const at::BFloat16* p, float out[4]) {
#pragma unroll
  for (int i = 0; i < 4; ++i) out[i] = bf16_to_f32(p + i);
}

// ---- kernel ----
// One CTA per (b,h). block=256 threads.
// Online softmax; accumulate output in registers (2 dims/thread).
__global__ void mla_paged_decode_h16_ckv512_kpe64_ps1_kernel(
    const at::BFloat16* __restrict__ q_nope,    // [B,16,512]
    const at::BFloat16* __restrict__ q_pe,      // [B,16,64]
    const at::BFloat16* __restrict__ ckv_cache, // [P,1,512]
    const at::BFloat16* __restrict__ kpe_cache, // [P,1,64]
    const int32_t* __restrict__ kv_indptr,      // [B+1]
    const int32_t* __restrict__ kv_indices,     // [N]
    float sm_scale,
    at::BFloat16* __restrict__ out,             // [B,16,512]
    float* __restrict__ lse,                    // [B,16]
    int B,
    int num_pages,
    int num_kv_indices)
{
  int bh = (int)blockIdx.x;
  int b = bh >> 4;
  int h = bh & 15;
  if (b >= B) return;

  int32_t beg = kv_indptr[b];
  int32_t end = kv_indptr[b + 1];

  // clamp
  beg = beg < 0 ? 0 : beg;
  end = end > num_kv_indices ? num_kv_indices : end;

  int L = (int)(end - beg);

  const int qn_base = (b * 16 + h) * 512;
  const int qp_base = (b * 16 + h) * 64;

  at::BFloat16* out_ptr = out + qn_base;
  float* lse_ptr = lse + (b * 16 + h);

  if (L <= 0) {
    for (int d = (int)threadIdx.x; d < 512; d += (int)blockDim.x) st_bf16(out_ptr + d, 0.0f);
    if (threadIdx.x == 0) *lse_ptr = neg_inf_f();
    return;
  }

  __shared__ float sQn[512];
  __shared__ float sQp[64];

  for (int d = (int)threadIdx.x; d < 512; d += (int)blockDim.x)
    sQn[d] = bf16_to_f32(q_nope + qn_base + d);
  for (int d = (int)threadIdx.x; d < 64; d += (int)blockDim.x)
    sQp[d] = bf16_to_f32(q_pe + qp_base + d);
  __syncthreads();

  float m = neg_inf_f();
  float s = 0.0f;

  int tid = (int)threadIdx.x;
  int d0 = tid * 2 + 0;
  int d1 = tid * 2 + 1;
  float o0 = 0.0f, o1 = 0.0f;

  constexpr int CKV_STRIDE = 512; // [P,1,512], page_size=1
  constexpr int KPE_STRIDE = 64;  // [P,1,64]

#pragma unroll 1
  for (int t = 0; t < L; ++t) {
    int32_t page = kv_indices[beg + t];
    if ((unsigned)page >= (unsigned)num_pages) continue;

    const at::BFloat16* kc = ckv_cache + (int64_t)page * CKV_STRIDE;
    const at::BFloat16* kp = kpe_cache + (int64_t)page * KPE_STRIDE;

    float local = 0.0f;

    // Dot(Qn, Kc): 512
    for (int i = tid * 4; i < 512; i += (int)blockDim.x * 4) {
      float kv[4];
      load_bf16x4_as_f32(kc + i, kv);
#pragma unroll
      for (int j = 0; j < 4; ++j) local = fmaf(sQn[i + j], kv[j], local);
    }
    // Dot(Qp, Kp): 64
    for (int i = tid * 4; i < 64; i += (int)blockDim.x * 4) {
      float kv[4];
      load_bf16x4_as_f32(kp + i, kv);
#pragma unroll
      for (int j = 0; j < 4; ++j) local = fmaf(sQp[i + j], kv[j], local);
    }

    float dot = block_reduce_sum<8>(local);

    float logit = dot * sm_scale;

    float new_m = fmaxf(m, logit);
    float alpha = __expf(m - new_m);
    float beta  = __expf(logit - new_m);
    float new_s = s * alpha + beta;

    // Accumulate output (unnormalized) with same rescaling
    if (d0 < 512) o0 = o0 * alpha + beta * bf16_to_f32(kc + d0);
    if (d1 < 512) o1 = o1 * alpha + beta * bf16_to_f32(kc + d1);

    m = new_m;
    s = new_s;
  }

  float inv_s = 1.0f / (s + 1e-20f);
  if (d0 < 512) st_bf16(out_ptr + d0, o0 * inv_s);
  if (d1 < 512) st_bf16(out_ptr + d1, o1 * inv_s);

  if (threadIdx.x == 0) {
    float lse_e = m + logf(s + 1e-20f);
    *lse_ptr = lse_e * 1.4426950408889634f; // 1/ln(2)
  }
}

void mla_paged_decode_h16_ckv512_kpe64_ps1_launch(
    const at::BFloat16* q_nope,
    const at::BFloat16* q_pe,
    const at::BFloat16* ckv_cache,
    const at::BFloat16* kpe_cache,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    float sm_scale,
    at::BFloat16* out,
    float* lse,
    int B,
    int num_pages,
    int num_kv_indices,
    cudaStream_t stream)
{
  dim3 grid((unsigned)(B * 16));
  dim3 block(256);

  mla_paged_decode_h16_ckv512_kpe64_ps1_kernel<<<grid, block, 0, stream>>>(
      q_nope, q_pe, ckv_cache, kpe_cache, kv_indptr, kv_indices, sm_scale,
      out, lse, B, num_pages, num_kv_indices);

  CUDA_CHECK(cudaGetLastError());
}

#include "kernel.h"

#include <ATen/cuda/CUDAContext.h>
#include <torch/extension.h>

#include <vector>

static void validate_inputs(
    const torch::Tensor& q_nope,
    const torch::Tensor& q_pe,
    const torch::Tensor& ckv_cache,
    const torch::Tensor& kpe_cache,
    const torch::Tensor& kv_indptr,
    const torch::Tensor& kv_indices,
    const torch::Tensor& sm_scale)
{
  CHECK_CUDA(q_nope);
  CHECK_CUDA(q_pe);
  CHECK_CUDA(ckv_cache);
  CHECK_CUDA(kpe_cache);
  CHECK_CUDA(kv_indptr);
  CHECK_CUDA(kv_indices);

  CHECK_CONTIGUOUS(q_nope);
  CHECK_CONTIGUOUS(q_pe);
  CHECK_CONTIGUOUS(ckv_cache);
  CHECK_CONTIGUOUS(kpe_cache);
  CHECK_CONTIGUOUS(kv_indptr);
  CHECK_CONTIGUOUS(kv_indices);

  CHECK_DTYPE(q_nope, torch::kBFloat16);
  CHECK_DTYPE(q_pe, torch::kBFloat16);
  CHECK_DTYPE(ckv_cache, torch::kBFloat16);
  CHECK_DTYPE(kpe_cache, torch::kBFloat16);
  CHECK_DTYPE(kv_indptr, torch::kInt32);
  CHECK_DTYPE(kv_indices, torch::kInt32);

  TORCH_CHECK(sm_scale.numel() == 1, "sm_scale must be a scalar tensor");
  TORCH_CHECK(sm_scale.dtype() == torch::kFloat32, "sm_scale must be float32");
  TORCH_CHECK(sm_scale.is_contiguous(), "sm_scale must be contiguous");

  TORCH_CHECK(q_nope.dim() == 3 && q_nope.size(1) == 16 && q_nope.size(2) == 512,
              "q_nope must be [B,16,512]");
  TORCH_CHECK(q_pe.dim() == 3 && q_pe.size(1) == 16 && q_pe.size(2) == 64,
              "q_pe must be [B,16,64]");
  TORCH_CHECK(q_pe.size(0) == q_nope.size(0), "q_pe batch must match q_nope batch");

  TORCH_CHECK(ckv_cache.dim() == 3 && ckv_cache.size(1) == 1 && ckv_cache.size(2) == 512,
              "ckv_cache must be [P,1,512]");
  TORCH_CHECK(kpe_cache.dim() == 3 && kpe_cache.size(1) == 1 && kpe_cache.size(2) == 64,
              "kpe_cache must be [P,1,64]");
  TORCH_CHECK(ckv_cache.size(0) == kpe_cache.size(0), "ckv_cache and kpe_cache num_pages mismatch");

  const int64_t B = q_nope.size(0);
  TORCH_CHECK(kv_indptr.dim() == 1 && kv_indptr.size(0) == B + 1,
              "kv_indptr must be [B+1]");
  TORCH_CHECK(kv_indices.dim() == 1, "kv_indices must be [N]");

  // Avoid any device->host scalar read in restricted sandboxes.
  TORCH_CHECK(sm_scale.device().is_cuda(),
              "sm_scale must be a CUDA float32 scalar tensor on the same device as q_nope");
  TORCH_CHECK(sm_scale.get_device() == q_nope.get_device(),
              "sm_scale must be on the same CUDA device as q_nope");
}

static float read_sm_scale_device(const torch::Tensor& sm_scale) {
  // Copy device scalar to host in a safe way (no fd tricks): use at::cuda::CUDAStream and cudaMemcpyAsync.
  float h = 0.0f;
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(sm_scale.get_device());
  cudaError_t err = cudaMemcpyAsync(&h, sm_scale.data_ptr<float>(), sizeof(float),
                                   cudaMemcpyDeviceToHost, stream);
  TORCH_CHECK(err == cudaSuccess, "cudaMemcpyAsync(sm_scale D2H) failed: ", cudaGetErrorString(err));
  err = cudaStreamSynchronize(stream);
  TORCH_CHECK(err == cudaSuccess, "cudaStreamSynchronize after sm_scale copy failed: ", cudaGetErrorString(err));
  return h;
}

std::vector<torch::Tensor> run(
    torch::Tensor q_nope,
    torch::Tensor q_pe,
    torch::Tensor ckv_cache,
    torch::Tensor kpe_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    torch::Tensor sm_scale)
{
  validate_inputs(q_nope, q_pe, ckv_cache, kpe_cache, kv_indptr, kv_indices, sm_scale);

  const int B = (int)q_nope.size(0);
  const int num_pages = (int)ckv_cache.size(0);
  const int num_kv_indices = (int)kv_indices.numel();

  auto out = torch::empty({B, 16, 512}, q_nope.options().dtype(torch::kBFloat16));
  auto lse = torch::empty({B, 16}, q_nope.options().dtype(torch::kFloat32));

  const float sm = read_sm_scale_device(sm_scale);

  cudaStream_t stream = at::cuda::getDefaultCUDAStream(q_nope.get_device());

  mla_paged_decode_h16_ckv512_kpe64_ps1_launch(
      (const at::BFloat16*)q_nope.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)q_pe.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)ckv_cache.data_ptr<at::BFloat16>(),
      (const at::BFloat16*)kpe_cache.data_ptr<at::BFloat16>(),
      (const int32_t*)kv_indptr.data_ptr<int32_t>(),
      (const int32_t*)kv_indices.data_ptr<int32_t>(),
      sm,
      (at::BFloat16*)out.data_ptr<at::BFloat16>(),
      (float*)lse.data_ptr<float>(),
      B,
      num_pages,
      num_kv_indices,
      stream);

  cudaError_t err = cudaGetLastError();
  TORCH_CHECK(err == cudaSuccess, "CUDA kernel launch failed: ", cudaGetErrorString(err));

  return {out, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function");
}
